import{_ as o,a as s}from"./chunks/electron-logo.opFE0ztr.js";import{_ as n,c as a,o as r,ah as e}from"./chunks/framework.RCw5T9E9.js";const _=JSON.parse('{"title":"Установка","description":"","frontmatter":{"title":"Установка"},"headers":[],"relativePath":"ru/install.md","filePath":"ru/install.md"}'),l={name:"ru/install.md"};function i(d,t,g,p,c,h){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="установка" tabindex="-1">Установка <a class="header-anchor" href="#установка" aria-label="Permalink to &quot;Установка&quot;">​</a></h1><p>Vue Inspector доступен в нескольких вариантах запуска, чтобы инструмент можно было использовать в разных рабочих средах и браузерах.</p><p>Выбор варианта зависит от ограничений среды, требований безопасности и предпочтительного способа работы.</p><div class="install-options"><a class="install-option-card" href="./extension"><span class="install-option-icon install-option-icon--brand" aria-hidden="true"><img src="'+o+'" alt="" width="32" height="32" loading="lazy" decoding="async"></span><span class="install-option-body"><span class="install-option-title">Расширение для браузера</span><span class="install-option-desc">Полный контроль над приложением.</span></span></a><a class="install-option-card" href="./standalone"><span class="install-option-icon install-option-icon--brand" aria-hidden="true"><img src="'+s+'" alt="" width="32" height="32" loading="lazy" decoding="async"></span><span class="install-option-body"><span class="install-option-title">Автономное приложение</span><span class="install-option-desc">Для корпоративных политик и любых браузеров.</span></span></a></div><h2 id="что-выбрать" tabindex="-1">Что выбрать? <a class="header-anchor" href="#что-выбрать" aria-label="Permalink to &quot;Что выбрать?&quot;">​</a></h2><ul><li><strong>Расширение для Chrome</strong> — если нужен постоянный доступ и полный набор возможностей: автозапуск, интеграция с <code>DevTools</code> и расширенные сценарии запуска внутри браузера.</li><li><strong>Автономное приложение</strong> — если установка расширений недоступна, действуют корпоративные ограничения или требуется независимый запуск.</li></ul><hr><h2 id="storage" tabindex="-1">Где хранятся настройки <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Где хранятся настройки {#storage}&quot;">​</a></h2><p>И <strong>расширение</strong>, и <strong>standalone</strong> держат <strong>один общий профиль</strong> настроек для браузера: после сохранения в Options те же значения подхватываются на <strong>любом сайте</strong>, где вы открыли инспектор. Настраивать заново под каждый домен не требуется.</p><p>Отличается только <strong>механизм</strong> хранения: у расширения это штатные хранилища Chrome для установленного компонента, у standalone — <strong>отдельное локальное хранилище</strong> приложения (без установки в <code>chrome://extensions</code>), специально заведённое под этот режим.</p><table tabindex="0"><thead><tr><th></th><th><strong>Расширение</strong></th><th><strong>Standalone (закладка)</strong></th></tr></thead><tbody><tr><td><strong>Настройки</strong> (опции, избранное, списки сайтов и т.п.)</td><td>Локальное хранилище <strong>расширения</strong> в профиле браузера: данные привязаны к установленной копии Vue Inspector, а не к конкретной вкладке.</td><td><strong>Собственное</strong> локальное хранилище standalone: то же по смыслу — одна база на все сайты, куда вы запускаете инструмент закладкой.</td></tr><tr><td><strong>Файлы оформления</strong> (фоны, сохранённые медиа из Customize и связанных мест)</td><td>Хранятся отдельно в <strong>браузерном хранилище</strong> в контексте расширения (копии файлов на диске профиля, не «на сайте»).</td><td>Попадают в <strong>то же единое</strong> хранилище standalone вместе с учётом его лимитов (см. <a href="/qa-tools/docs/ru/options/customize.html">Персонализация</a>).</td></tr><tr><td><strong>Между сайтами</strong></td><td>Один набор настроек на все домены в этом профиле браузера.</td><td>Один набор настроек на все домены: хранилище <strong>не привязано</strong> к origin страницы, поэтому переиспользование между сайтами такое же, как у расширения.</td></tr></tbody></table><p>Подробнее про лимиты медиа в Customize — в <a href="/qa-tools/docs/ru/options/customize.html">Персонализация</a>.</p><p><strong>Сохранение и перенос:</strong> обычные правки в Options <strong>пишутся автоматически</strong> (с небольшой задержкой). <strong>Расширение</strong> дублирует набор настроек в <strong>IndexedDB</strong> и в <strong><code>chrome.storage.local</code></strong>; <strong>standalone</strong> хранит снимок в <strong>своём центральном KV-хранилище</strong> (IndexedDB), медиа — отдельно с лимитом объёма. Кнопки <strong>Export / Import / Reset</strong> в General дают файл JSON и полный сброс; чем отличается состав экспорта и импорт между режимами — в <a href="/qa-tools/docs/ru/options/settings_management.html">Менеджер настроек</a>.</p>',13)])])}const f=n(l,[["render",i]]);export{_ as __pageData,f as default};
